import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  User, Shield, Mail, Trash2, Edit, Save, 
  X, Loader2, AlertCircle, Crown, Users, Key, ChevronDown
} from 'lucide-react';

const Perfil = () => {
  const [perfil, setPerfil] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [novoNome, setNovoNome] = useState('');
  const [novaSenha, setNovaSenha] = useState('');
  const [erroLocal, setErroLocal] = useState(null);

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();

      if (!user) {
        setErroLocal("Sessão expirada. Faça login novamente.");
        return;
      }

      const { data: meuPerfil, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .maybeSingle();

      if (profileError) throw profileError;

      if (meuPerfil) {
        setPerfil(meuPerfil);
        setNovoNome(meuPerfil.nome || '');

        // Se for proprietário, carrega a lista de todos os usuários
        if (meuPerfil.tipo_usuario === 'proprietario') {
          const { data: lista } = await supabase
            .from('profiles')
            .select('*')
            .order('nome', { ascending: true });
          
          if (lista) setUsuarios(lista);
        }
      }
    } catch (err) {
      setErroLocal("Não foi possível carregar os dados.");
    } finally {
      setLoading(false);
    }
  };

  const atualizarNome = async () => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({ nome: novoNome })
        .eq('id', perfil.id);

      if (error) throw error;
      setPerfil({ ...perfil, nome: novoNome });
      alert("Nome atualizado com sucesso!");
    } catch (err) {
      alert("Erro ao atualizar o nome.");
    }
  };

  const alterarSenha = async () => {
    if (novaSenha.length < 6) {
      alert("A senha deve ter pelo menos 6 caracteres.");
      return;
    }
    try {
      const { error } = await supabase.auth.updateUser({ password: novaSenha });
      if (error) throw error;
      alert("Senha alterada com sucesso!");
      setNovaSenha('');
    } catch (err) {
      alert("Erro ao alterar senha: " + err.message);
    }
  };

  const mudarCargo = async (usuarioId, novoCargo) => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({ tipo_usuario: novoCargo })
        .eq('id', usuarioId);

      if (error) throw error;
      setUsuarios(usuarios.map(u => u.id === usuarioId ? { ...u, tipo_usuario: novoCargo } : u));
    } catch (err) {
      alert("Erro ao mudar cargo.");
    }
  };

  const excluirUsuario = async (id, nome) => {
    if (id === perfil.id) return;
    if (window.confirm(`Excluir permanentemente o acesso de ${nome}?`)) {
      const { error } = await supabase.from('profiles').delete().eq('id', id);
      if (!error) {
        setUsuarios(usuarios.filter(u => u.id !== id));
      }
    }
  };

  if (loading) return (
    <div style={containerCenter}>
      <Loader2 className="animate-spin" size={48} color="#4361ee" />
      <p style={{ color: '#64748b', fontWeight: 500 }}>Sincronizando...</p>
    </div>
  );

  return (
    <div style={{ padding: '40px 20px', maxWidth: '900px', margin: '0 auto', paddingBottom: '100px' }}>
      <header style={{ marginBottom: '40px' }}>
        <h1 style={titleStyle}>Meu Perfil</h1>
        <p style={{ color: '#64748b', fontSize: '1.1rem' }}>Gerencie suas informações e acessos.</p>
      </header>

      {/* SEÇÃO 1: DADOS DO USUÁRIO LOGADO */}
      <section style={mainCardStyle}>
        <div style={{ flex: 1, minWidth: '300px' }}>
          <h3 style={sectionTitleStyle}><User size={20} /> Suas Informações</h3>
          
          <div style={{ marginBottom: '25px' }}>
            <label style={labelStyle}>Nome de Exibição</label>
            <div style={{ display: 'flex', gap: '10px' }}>
              <input 
                value={novoNome} 
                onChange={(e) => setNovoNome(e.target.value)}
                style={inputStyle}
              />
              <button onClick={atualizarNome} style={btnPrimaryStyle} title="Salvar Nome">
                <Save size={20} />
              </button>
            </div>
          </div>

          <div style={infoGrid}>
            <div style={infoItem}>
              <label style={labelStyle}>E-mail</label>
              <div style={infoValue}><Mail size={16} /> {perfil?.email}</div>
            </div>
            <div style={infoItem}>
              <label style={labelStyle}>Nível de Acesso</label>
              <div style={badgeStyle(perfil?.tipo_usuario)}>
                <Shield size={14} /> {perfil?.tipo_usuario}
              </div>
            </div>
          </div>
        </div>

        <div style={dividerHorizontal} />

        <div style={{ flex: 1, minWidth: '300px' }}>
          <h3 style={sectionTitleStyle}><Key size={20} /> Segurança</h3>
          <label style={labelStyle}>Nova Senha</label>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <input 
              type="password" 
              placeholder="Mínimo 6 caracteres" 
              value={novaSenha}
              onChange={(e) => setNovaSenha(e.target.value)}
              style={inputStyle}
            />
            <button onClick={alterarSenha} style={btnSecondaryStyle}>
              Atualizar Senha
            </button>
          </div>
        </div>
      </section>

      {/* SEÇÃO 2: LISTA DE USUÁRIOS (APENAS PARA PROPRIETÁRIO) */}
      {perfil?.tipo_usuario === 'proprietario' && (
        <section style={{ marginTop: '50px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '25px' }}>
            <div style={iconBoxStyle}><Users size={22} color="#fff" /></div>
            <h3 style={{ fontSize: '1.5rem', fontWeight: 800, color: '#0f172a', margin: 0 }}>Gestão de Acessos</h3>
          </div>

          <div style={{ display: 'grid', gap: '15px' }}>
            {usuarios.map(u => (
              <div key={u.id} style={userRowStyle}>
                <div style={smallAvatar}>{u.nome?.charAt(0) || '?'}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, color: '#1e293b' }}>{u.nome}</div>
                  <div style={{ fontSize: '0.85rem', color: '#94a3b8' }}>{u.email}</div>
                </div>

                <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                  {u.id !== perfil.id ? (
                    <>
                      <div style={selectWrapper}>
                        <select 
                          value={u.tipo_usuario} 
                          onChange={(e) => mudarCargo(u.id, e.target.value)}
                          style={selectStyle}
                        >
                          <option value="comum">Comum</option>
                          <option value="proprietario">Proprietário</option>
                        </select>
                        <ChevronDown size={14} style={selectIcon} />
                      </div>
                      <button onClick={() => excluirUsuario(u.id, u.nome)} style={deleteBtn}>
                        <Trash2 size={18} />
                      </button>
                    </>
                  ) : (
                    <span style={badgeStyle(u.tipo_usuario)}>Você</span>
                  )}
                </div>
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

// --- ESTILOS DESIGN SYSTEM ANTERIOR ---
const containerCenter = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '70vh', gap: '20px' };
const titleStyle = { fontSize: '2.4rem', fontWeight: 900, color: '#0f172a', marginBottom: '8px', letterSpacing: '-0.02em' };
const mainCardStyle = { 
  background: '#fff', padding: '40px', borderRadius: '32px', 
  boxShadow: '0 20px 25px -5px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9',
  display: 'flex', gap: '40px', flexWrap: 'wrap'
};
const sectionTitleStyle = { display: 'flex', alignItems: 'center', gap: '10px', fontSize: '1.2rem', fontWeight: 800, color: '#1e293b', marginBottom: '25px' };
const labelStyle = { fontSize: '0.75rem', fontWeight: 800, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '10px', display: 'block' };
const inputStyle = { padding: '12px 16px', borderRadius: '14px', border: '2px solid #f1f5f9', fontSize: '1rem', outline: 'none', width: '100%', transition: 'all 0.2s' };
const infoGrid = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginTop: '10px' };
const infoItem = { background: '#f8fafc', padding: '15px', borderRadius: '16px' };
const infoValue = { display: 'flex', alignItems: 'center', gap: '8px', color: '#475569', fontWeight: 600, fontSize: '0.9rem' };
const btnPrimaryStyle = { background: '#4361ee', color: '#fff', border: 'none', borderRadius: '14px', padding: '0 15px', cursor: 'pointer' };
const btnSecondaryStyle = { background: '#0f172a', color: '#fff', border: 'none', borderRadius: '14px', padding: '12px', fontWeight: 700, cursor: 'pointer' };
const dividerHorizontal = { width: '1px', background: '#f1f5f9', alignSelf: 'stretch' };
const iconBoxStyle = { background: '#4361ee', padding: '8px', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const userRowStyle = { display: 'flex', alignItems: 'center', padding: '16px 20px', background: '#fff', borderRadius: '20px', border: '1px solid #f1f5f9', gap: '15px' };
const smallAvatar = { width: '42px', height: '42px', borderRadius: '12px', background: '#e2e8f0', color: '#475569', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800 };
const selectWrapper = { position: 'relative', display: 'flex', alignItems: 'center' };
const selectStyle = { 
  appearance: 'none', padding: '8px 30px 8px 12px', borderRadius: '10px', 
  border: '1px solid #e2e8f0', fontSize: '0.85rem', fontWeight: 600, 
  background: '#fff', cursor: 'pointer', color: '#475569' 
};
const selectIcon = { position: 'absolute', right: '10px', pointerEvents: 'none', color: '#94a3b8' };
const deleteBtn = { background: '#fff1f2', border: 'none', color: '#ef4444', borderRadius: '10px', padding: '10px', cursor: 'pointer' };

const badgeStyle = (tipo) => ({
  display: 'inline-flex', alignItems: 'center', gap: '6px', padding: '6px 12px', borderRadius: '10px', 
  fontSize: '0.75rem', fontWeight: 800,
  backgroundColor: tipo === 'proprietario' ? '#4361ee15' : '#f1f5f9',
  color: tipo === 'proprietario' ? '#4361ee' : '#64748b',
  textTransform: 'uppercase'
});

export default Perfil;
